// ==UserScript==
// @name         本地图片管理(支持切换角色)
// @version      111.0
// @description  后台自动清理，弹窗内可切换角色浏览图库
// @author       Assistant
// @match        *://*/*
// @grant        none
// ==/UserScript==

(function() {
    'use strict';
    const CMD='browse-images', BTN='打开图片管理', PS=200, SK='lim_keep_count';
    var keep=parseInt(localStorage.getItem(SK))||0, idle=null, countdownInterval=null;

    const H=()=>{let h={'Content-Type':'application/json'};if(typeof SillyTavern.getRequestHeaders==='function'){return{...SillyTavern.getRequestHeaders(),...h};}return h;};

    async function del(fn, file){
        const hd=H();
        const raw=`${fn}/${file}`;
        const ef=encodeURIComponent(fn), ef2=encodeURIComponent(file);
        const paths=[raw,`/${raw}`,`user/images/${raw}`,`/user/images/${raw}`,`images/${raw}`,`/images/${raw}`,`${ef}/${ef2}`,`/${ef}/${ef2}`,`user/images/${ef}/${ef2}`,`/user/images/${ef}/${ef2}`,file,`/${file}`,`user/images/${fn}/${ef2}`,`data/default-user/images/${raw}`,`data/${raw}`];
        for(const p of paths){
            try{
                const r=await fetch('/api/images/delete',{method:'POST',headers:hd,body:JSON.stringify({path:p})});
                if(r.ok)return{success:true};
            }catch(e){}
        }
        return{success:false};
    }

    function clearCountdown(){if(countdownInterval){clearInterval(countdownInterval);countdownInterval=null;}}

    function resetIdle(){
        if(idle){clearTimeout(idle);idle=null;}
        clearCountdown();
        const status=document.getElementById('lim-clean-status');
        if(status) status.textContent='';
    }

    // 后台清理（不依赖弹窗）
    async function backgroundCheck(){
        const fn=getCharName();
        if(!fn||keep<=0) return;
        try{
            const h=H();
            const r=await fetch('/api/images/list',{method:'POST',headers:h,body:JSON.stringify({folder:fn})});
            if(!r.ok) return;
            const d=await r.json();
            let files=[];
            if(Array.isArray(d))files=d;else if(d.images)files=d.images;else if(d.files)files=d.files;
            if(files.length<=keep) return;
            scheduleBackground(fn,files);
        }catch(e){}
    }

    function scheduleBackground(fn,files){
        resetIdle();
        idle=setTimeout(async()=>{
            files.sort((a,b)=>{const na=typeof a==='string'?a:(a.name||a.path);const nb=typeof b==='string'?b:(b.name||b.path);return na.localeCompare(nb);});
            const oldest=files[0];
            const name=typeof oldest==='string'?oldest:(oldest.name||oldest.path.split('/').pop());
            const r=await del(fn,name);
            if(r.success){
                if(typeof toastr!=='undefined') toastr.success(`已自动删除一张最早图片: ${name}`);
            }else{
                if(typeof toastr!=='undefined') toastr.warning('自动删除失败');
            }
            backgroundCheck();
        },30*1000);
    }

    function waitForST(){
        if(window.SillyTavern&&SillyTavern.getContext&&typeof $!=='undefined'&&typeof eventOn==='function'){
            init();
        }else setTimeout(waitForST,300);
    }

    function init(){
        try{
            SillyTavern.getContext().SlashCommandParser.addCommandObject({
                name:CMD,aliases:['查看图片','浏览图片','删除图片'],description:'浏览并删除本地角色图片',callback:slash,returns:'',args:[{name:'角色名',description:'可选',required:false}]
            });
            if(typeof appendInexistentScriptButtons==='function'&&typeof getButtonEvent==='function'){
                appendInexistentScriptButtons([{name:BTN,visible:true}]);
                eventOn(getButtonEvent(BTN),()=>{
                    const fn=getCharName();
                    if(!fn){if(typeof toastr!=='undefined')toastr.warning('无法获取当前角色名');return;}
                    open(fn);
                });
            }
            backgroundCheck();
            if(typeof tavern_events!=='undefined'){
                eventOn(tavern_events.MESSAGE_RECEIVED,()=>{resetIdle();backgroundCheck();});
                eventOn(tavern_events.MESSAGE_SWIPED,()=>{resetIdle();backgroundCheck();});
                eventOn(tavern_events.CHAT_CHANGED,()=>{resetIdle();backgroundCheck();});
                eventOn(tavern_events.GENERATION_ENDED,()=>{resetIdle();backgroundCheck();});
            }
        }catch(e){console.error('[图片管理]',e);}
    }

    async function slash(args,msg){
        let fn='';
        if(typeof args==='string')fn=args.trim();
        else if(Array.isArray(args)&&args.length>0)fn=String(args[0]).trim();
        if(!fn)fn=getCharName();
        if(!fn){if(msg?.chat_message)msg.chat_message.innerHTML='❌ 无法获取角色名';return'';}
        open(fn);
        return'';
    }

    function open(fn){
        const old=document.getElementById('lim-overlay');if(old)old.remove();
        const ov=document.createElement('div');ov.id='lim-overlay';
        Object.assign(ov.style,{position:'fixed',top:'0',left:'0',width:'100vw',height:'100vh',background:'rgba(10,10,15,0.8)',backdropFilter:'blur(10px)',zIndex:'2147483647',display:'flex',alignItems:'center',justifyContent:'center'});
        ov.onclick=e=>{if(e.target===ov)ov.remove();resetIdle();backgroundCheck();};
        const td=(window.top&&window.top.document)?window.top.document:document;
        const pp=document.createElement('div');
        pp.style.cssText='background:rgba(28,28,38,0.95);border:1px solid rgba(255,255,255,0.08);border-radius:16px;width:96vw;max-width:1400px;max-height:80vh;display:flex;flex-direction:column;padding:16px;box-shadow:0 20px 40px rgba(0,0,0,0.5);';
        const hd=document.createElement('div');hd.style.cssText='display:flex;align-items:center;gap:8px;margin-bottom:12px;flex-wrap:wrap;';

        // 角色切换下拉菜单
        const charSelect=document.createElement('select');
        charSelect.style.cssText='background:rgba(0,0,0,0.3);border:1px solid rgba(255,255,255,0.15);color:#ccc;border-radius:4px;padding:2px 4px;font-size:0.8em;max-width:120px;';
        const allChars=SillyTavern.characters||[];
        allChars.forEach(c=>{
            if(c&&c.name){
                const opt=document.createElement('option');
                opt.value=c.name;
                opt.textContent=c.name;
                if(c.name===fn) opt.selected=true;
                charSelect.appendChild(opt);
            }
        });
        const sc=document.createElement('div');sc.id='lim-popup-container';sc.style.cssText='flex:1;overflow-y:auto;min-height:200px;';sc.innerHTML='<div style="color:#aaa;text-align:center;padding:40px;">正在加载...</div>';
        const statusEl=document.createElement('span');statusEl.id='lim-clean-status';statusEl.style.cssText='font-size:0.75em;color:#aaa;margin-left:auto;';

        charSelect.onchange=async()=>{
            const newFn=charSelect.value;
            if(newFn){
                resetIdle();
                fn=newFn; // 更新 fn 变量，使后续操作针对新角色
                load(newFn,0,sc,statusEl,charSelect);
            }
        };

        const ki=document.createElement('input');ki.type='number';ki.min=0;ki.value=keep;ki.style.cssText='width:55px;background:rgba(0,0,0,0.3);border:1px solid rgba(255,255,255,0.15);color:#ccc;border-radius:4px;padding:2px 4px;font-size:0.8em;';
        const cb=document.createElement('button');cb.textContent='确认';cb.style.cssText='background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:#ccc;padding:3px 10px;border-radius:4px;cursor:pointer;font-size:0.8em;';
        cb.onclick=()=>{keep=parseInt(ki.value)||0;localStorage.setItem(SK,keep);if(typeof toastr!=='undefined')toastr.success(`保留数量已设为 ${keep} 张`);resetIdle();backgroundCheck();};

        const cn=document.createElement('button');cn.textContent='立即清理';cn.style.cssText='background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:#ccc;padding:3px 10px;border-radius:4px;cursor:pointer;font-size:0.8em;';
        cn.onclick=async()=>{
            if(keep<=0){alert('请先设置保留数量');return;}
            const currentFn=charSelect.value;
            try{
                const h=H();
                const r=await fetch('/api/images/list',{method:'POST',headers:h,body:JSON.stringify({folder:currentFn})});
                if(!r.ok)throw new Error(`获取列表失败 (${r.status})`);
                const d=await r.json();
                let files=[];
                if(Array.isArray(d))files=d;else if(d.images)files=d.images;else if(d.files)files=d.files;
                if(files.length<=keep){alert(`当前图片数量 (${files.length}) 未超过 ${keep}，无需清理`);return;}
                const excess=files.length-keep;
                if(!confirm(`当前图片 ${files.length} 张，保留 ${keep} 张，
将立即删除最早的 ${excess} 张图片。
确定继续？`))return;
                resetIdle();
                statusEl.textContent='正在批量删除...';
                files.sort((a,b)=>{const na=typeof a==='string'?a:(a.name||a.path);const nb=typeof b==='string'?b:(b.name||b.path);return na.localeCompare(nb);});
                const toDel=files.slice(0,excess);
                let ok=0;
                for(const f of toDel){
                    const name=typeof f==='string'?f:(f.name||f.path.split('/').pop());
                    const r=await del(currentFn,name);
                    if(r.success) ok++;
                }
                if(typeof toastr!=='undefined') toastr.success(`已删除 ${ok} 张图片`);
                load(currentFn,0,sc,statusEl,charSelect);
            }catch(e){console.error(e);alert('清理出错: '+e.message);}
        };

        const cl=document.createElement('button');cl.innerHTML='✕';cl.style.cssText='background:none;border:none;color:#999;font-size:1.3em;cursor:pointer;';cl.onclick=()=>ov.remove();

        hd.appendChild(charSelect);
        hd.appendChild(ki);hd.appendChild(cb);hd.appendChild(cn);hd.appendChild(cl);hd.appendChild(statusEl);pp.appendChild(hd);
        pp.appendChild(sc);
        ov.appendChild(pp);td.body.appendChild(ov);
        load(fn,0,sc,statusEl,charSelect);
    }

    async function load(fn,start,ct,statusEl,charSelect){
        try{
            const h=H();
            const r=await fetch('/api/images/list',{method:'POST',headers:h,body:JSON.stringify({folder:fn})});
            if(!r.ok)throw new Error(`请求失败 (${r.status})`);
            const d=await r.json();
            let files=[];
            if(Array.isArray(d))files=d;else if(d.images)files=d.images;else if(d.files)files=d.files;
            if(files.length===0){ct.innerHTML='<p style="color:#aaa;text-align:center;padding:40px;">📭 暂无图片</p>';if(statusEl)statusEl.textContent='';return;}
            files.sort((a,b)=>{const na=typeof a==='string'?a:(a.name||a.path);const nb=typeof b==='string'?b:(b.name||b.path);return nb.localeCompare(na);});
            const total=files.length;
            if(start>=total) start=Math.max(0, total-PS);
            const batch=files.slice(start,start+PS);
            const pages=Math.ceil(total/PS);
            const cur=Math.floor(start/PS)+1;
            // 更新下拉菜单中当前角色可能被选中
            if(charSelect){
                for(let i=0;i<charSelect.options.length;i++){
                    if(charSelect.options[i].value===fn) charSelect.selectedIndex=i;
                }
            }
            // 标题显示在状态栏（或新增一个标题元素），这里我们利用状态栏显示文件名
            if(statusEl) statusEl.textContent=`${fn} (${total}张)` + (keep>0 && total>keep ? ` - 30s后自动删除1张最早图片` : '');
            ct.innerHTML='';
            if(pages>1){
                const nav=document.createElement('div');nav.style.cssText='display:flex;justify-content:center;align-items:center;gap:12px;margin:10px 0;color:#ccc;';
                if(start>0){
                    const prev=document.createElement('button');prev.textContent='上一页';prev.style.cssText='background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:#ccc;padding:4px 12px;border-radius:4px;cursor:pointer;';
                    prev.onclick=()=>{resetIdle();load(fn,start-PS,ct,statusEl,charSelect);};nav.appendChild(prev);
                }
                const pageText=document.createElement('span');pageText.textContent=`${cur}/${pages}`;pageText.style.cssText='display:inline-flex;align-items:center;';
                nav.appendChild(pageText);
                if(start+PS<total){
                    const next=document.createElement('button');next.textContent='下一页';next.style.cssText='background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:#ccc;padding:4px 12px;border-radius:4px;cursor:pointer;';
                    next.onclick=()=>{resetIdle();load(fn,start+PS,ct,statusEl,charSelect);};nav.appendChild(next);
                }
                ct.appendChild(nav);
            }
            const grid=document.createElement('div');grid.className='lim-image-grid';grid.style.cssText='display:grid;grid-template-columns:repeat(auto-fill, minmax(180px, 1fr));gap:10px;';
            grid.addEventListener('click',e=>{
                const t=e.target;
                if(t.tagName==='IMG'&&t.closest('.lim-image-grid')){
                    e.preventDefault();
                    resetIdle();
                    const idx=parseInt(t.dataset.index);
                    if(!isNaN(idx)&&idx>=0&&idx<files.length){
                        const f=files[idx];
                        const name=typeof f==='string'?f:(f.name||f.path.split('/').pop());
                        const url='/user/images/'+encodeURIComponent(fn)+'/'+encodeURIComponent(name);
                        showPreview(url, files, idx, fn);
                    }
                }
            });
            for(let i=0;i<batch.length;i++){
                const f=batch[i];
                const globalIdx=start+i;
                const name=typeof f==='string'?f:(f.name||f.path.split('/').pop());
                const url='/user/images/'+encodeURIComponent(fn)+'/'+encodeURIComponent(name);
                const card=document.createElement('div');card.style.cssText='background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06);border-radius:8px;overflow:hidden;transition:transform 0.2s;';
                card.onmouseenter=()=>card.style.transform='translateY(-2px)';card.onmouseleave=()=>card.style.transform='';
                const iw=document.createElement('div');iw.style.cssText='width:100%;padding-bottom:100%;position:relative;background:rgba(0,0,0,0.2);';
                const img=document.createElement('img');
                img.src=url;img.loading='lazy';img.alt=name;
                img.dataset.index=globalIdx;
                img.style.cssText='position:absolute;top:0;left:0;width:100%;height:100%;object-fit:contain;cursor:zoom-in;';
                iw.appendChild(img);
                const info=document.createElement('div');info.style.cssText='padding:6px 8px;';
                const ns=document.createElement('div');ns.textContent=name;ns.style.cssText='font-size:0.7em;color:#bbb;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
                const db=document.createElement('button');db.textContent='删除';db.style.cssText='margin-top:4px;width:100%;padding:3px 0;background:transparent;color:#aaa;border:1px solid rgba(255,255,255,0.15);border-radius:4px;cursor:pointer;font-size:0.7em;';
                db.onclick=async(e)=>{
                    e.stopPropagation();resetIdle();
                    if(!confirm(`删除 ${name}？`))return;
                    const r=await del(fn,name);
                    if(r.success){
                        load(fn, start, ct, statusEl, charSelect);
                        if(typeof toastr!=='undefined')toastr.success('图片已删除');
                    }else alert('删除失败');
                };
                info.appendChild(ns);info.appendChild(db);card.appendChild(iw);card.appendChild(info);grid.appendChild(card);
            }
            ct.appendChild(grid);
        }catch(e){ct.innerHTML='<p style="color:#f66;text-align:center;padding:40px;">❌ '+e.message+'</p>';}
    }

    function showPreview(url, files, idx, folderName){
        const old=document.getElementById('lim-preview-overlay');if(old)old.remove();
        const td=(window.top&&window.top.document)?window.top.document:document;
        const ov=document.createElement('div');ov.id='lim-preview-overlay';
        ov.style.cssText='position:fixed;top:0;left:0;width:100vw;height:100vh;background:rgba(0,0,0,0.95);z-index:2147483648;display:flex;align-items:center;justify-content:center;cursor:zoom-out;';
        ov.onclick=e=>{if(e.target===ov)ov.remove();resetIdle();backgroundCheck();};
        const img=document.createElement('img');img.src=url;
        img.style.cssText='max-width:85vw;max-height:85vh;object-fit:contain;border-radius:8px;transition:opacity 0.2s;';
        ov.appendChild(img);
        if(files && files.length>0){
            let currentIdx=idx;
            const updateImage=(newIdx)=>{
                const f=files[newIdx];
                const name=typeof f==='string'?f:(f.name||f.path.split('/').pop());
                img.src='/user/images/'+encodeURIComponent(folderName)+'/'+encodeURIComponent(name);
            };
            const left=document.createElement('div');left.innerHTML='‹';
            left.style.cssText='position:absolute;left:10px;top:50%;transform:translateY(-50%);font-size:60px;color:rgba(255,255,255,0.6);cursor:pointer;user-select:none;padding:10px;transition:color 0.2s;z-index:1;';
            left.onmouseover=()=>left.style.color='#fff';left.onmouseout=()=>left.style.color='rgba(255,255,255,0.6)';
            left.onclick=(e)=>{e.stopPropagation();if(currentIdx>0){currentIdx--;updateImage(currentIdx);resetIdle();backgroundCheck();}};
            ov.appendChild(left);
            const right=document.createElement('div');right.innerHTML='›';
            right.style.cssText='position:absolute;right:10px;top:50%;transform:translateY(-50%);font-size:60px;color:rgba(255,255,255,0.6);cursor:pointer;user-select:none;padding:10px;transition:color 0.2s;z-index:1;';
            right.onmouseover=()=>right.style.color='#fff';right.onmouseout=()=>right.style.color='rgba(255,255,255,0.6)';
            right.onclick=(e)=>{e.stopPropagation();if(currentIdx<files.length-1){currentIdx++;updateImage(currentIdx);resetIdle();backgroundCheck();}};
            ov.appendChild(right);
            const keyHandler=e=>{
                if(e.key==='ArrowLeft'&&currentIdx>0){currentIdx--;updateImage(currentIdx);resetIdle();backgroundCheck();}
                else if(e.key==='ArrowRight'&&currentIdx<files.length-1){currentIdx++;updateImage(currentIdx);resetIdle();backgroundCheck();}
                else if(e.key==='Escape')ov.remove();
            };
            document.addEventListener('keydown',keyHandler);
            const wheelHandler=e=>{
                e.preventDefault();
                if(e.deltaY<0 && currentIdx>0){currentIdx--;updateImage(currentIdx);resetIdle();backgroundCheck();}
                else if(e.deltaY>0 && currentIdx<files.length-1){currentIdx++;updateImage(currentIdx);resetIdle();backgroundCheck();}
            };
            ov.addEventListener('wheel',wheelHandler,{passive:false});
            ov.addEventListener('remove',()=>document.removeEventListener('keydown',keyHandler));
        }
        td.body.appendChild(ov);
    }

    function getCharName(){
        try{
            if(typeof SillyTavern!=='undefined'&&typeof SillyTavern.this_chid!=='undefined'&&SillyTavern.characters){const c=SillyTavern.characters[SillyTavern.this_chid];if(c?.name)return c.name;}
            const ctx=SillyTavern?.getContext?.();
            if(ctx?.name2)return ctx.name2;
            if(ctx?.chat){for(let i=ctx.chat.length-1;i>=0;i--){if(!ctx.chat[i].is_user&&ctx.chat[i].name)return ctx.chat[i].name;}}
            if(window.SillyTavern?.characters&&window.SillyTavern?.this_chid!==undefined){const c=window.SillyTavern.characters[window.SillyTavern.this_chid];if(c?.name)return c.name;}
        }catch(e){}
        return null;
    }

    waitForST();
})();
